// ── Input data ────────────────────────────────────────────────
const row = $('Loop: oferta por oferta').item.json;
const html = String($input.item.json.data || $input.item.json.body || '');

// ── JSON-LD extraction ────────────────────────────────────────
let ld = {};
const ldMatch = html.match(/<script[^>]+type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/i);
if (ldMatch && ldMatch[1]) {
  try {
    const parsed = JSON.parse(ldMatch[1].trim());
    if (Array.isArray(parsed['@graph'])) {
      ld = parsed['@graph'].find(function(n) {
        return n['@type'] === 'Vehicle' || n['@type'] === 'Car';
      }) || {};
    } else {
      ld = parsed;
    }
  } catch(e) { ld = {}; }
}

function safeStr(v) {
  return (v !== null && v !== undefined) ? String(v).trim() : null;
}

// ── image_url / images ────────────────────────────────────────
var image_url = null;
var images_arr = [];
if (ld['image']) {
  if (Array.isArray(ld['image'])) {
    images_arr = ld['image'].filter(function(i) { return typeof i === 'string' && i; });
    if (images_arr.length === 0) {
      images_arr = ld['image'].map(function(i) { return i && i.url ? i.url : null; }).filter(Boolean);
    }
    if (images_arr.length > 0) image_url = images_arr[0];
  } else if (typeof ld['image'] === 'string' && ld['image']) {
    image_url = ld['image'];
    images_arr = [image_url];
  } else if (ld['image'] && ld['image']['url']) {
    image_url = ld['image']['url'];
    images_arr = [image_url];
  }
}
if (!image_url) {
  var imgMatches = [...html.matchAll(/"(https:\/\/(?:img[^"]*autohero|cdn[^"]*autohero)[^"]+)"/gi)];
  if (imgMatches.length > 0) {
    images_arr = [...new Set(imgMatches.map(function(m) { return m[1].replace(/\\/g, ''); }))].slice(0, 10);
    image_url = images_arr[0];
  }
}

// Galeria completa: normalizar todas las fotos al mismo tamano y deduplicar
if (images_arr.length <= 1) {
  var _galRaw = [...html.matchAll(/https:\/\/img-eu-c1\.autohero\.com\/img\/[a-z0-9]+\/(?:exterior|interior)\/\d+\/\d+x\d+-[a-z0-9]+\.jpg/gi)].map(function(m){ return m[0]; });
  var _seen = {}; var _gal = [];
  for (var _gi = 0; _gi < _galRaw.length; _gi++) {
    var _n = _galRaw[_gi].replace(/\/\d+x\d+-/, '/768x432-');
    if (!_seen[_n]) { _seen[_n] = 1; _gal.push(_n); }
  }
  if (_gal.length > 0) { images_arr = _gal.slice(0, 15); image_url = images_arr[0]; }
}

function normalizeBody(raw) {
  var s = String(raw || '').toLowerCase();
  if (!s) return '';
  if (s.indexOf('suv') !== -1 || s.indexOf('4x4') !== -1 || s.indexOf('todo') !== -1) return 'SUV';
  if (s.indexOf('pick') !== -1) return 'Pick Up';
  if (s.indexOf('furgon') !== -1 || s.indexOf('van') !== -1 || s.indexOf('comercial') !== -1) return 'Furgoneta';
  if (s.indexOf('familiar') !== -1 || s.indexOf('estate') !== -1 || s.indexOf('combi') !== -1) return 'Familiar';
  if (s.indexOf('monovolum') !== -1 || s.indexOf('mpv') !== -1) return 'Monovolumen';
  if (s.indexOf('coup') !== -1) return 'Coupé';
  if (s.indexOf('cabrio') !== -1 || s.indexOf('descapotable') !== -1) return 'Cabrio';
  if (s.indexOf('pequeñ') !== -1 || s.indexOf('pequen') !== -1 || s.indexOf('compact') !== -1 || s.indexOf('ciudad') !== -1 || s.indexOf('utilitario') !== -1) return 'Compacto';
  if (s.indexOf('berlina') !== -1 || s.indexOf('sedan') !== -1 || s.indexOf('turismo') !== -1 || s.indexOf('hatchback') !== -1) return 'Berlina';
  return raw;
}

// ── body_type ─────────────────────────────────────────────────
var body_type = normalizeBody(safeStr(ld['bodyType']));

// ── doors ─────────────────────────────────────────────────────
var doors = null;
var doorsRaw = safeStr(ld['numberOfDoors']);
if (doorsRaw) {
  var d = parseInt(doorsRaw, 10);
  if (!isNaN(d) && d > 0) doors = d;
}

// ── seats ─────────────────────────────────────────────────────
var seats = null;
var seatsRaw = safeStr(ld['seatingCapacity']);
if (seatsRaw) {
  var s = parseInt(seatsRaw, 10);
  if (!isNaN(s) && s > 0) seats = s;
}

// ── color ─────────────────────────────────────────────────────
var color = safeStr(ld['vehicleInteriorColor']);
if (!color) {
  var metaMatch = html.match(/<meta[^>]+name=["']description["'][^>]+content=["']([^"']+)["']/i);
  if (!metaMatch) {
    metaMatch = html.match(/<meta[^>]+content=["']([^"']+)["'][^>]+name=["']description["']/i);
  }
  if (metaMatch && metaMatch[1]) {
    var firstWord = metaMatch[1].trim().split(/\s+/)[0];
    if (firstWord && firstWord.length > 2) color = firstWord;
  }
}

// ── fuel ──────────────────────────────────────────────────────
var fuel = null;
var fuelRaw = safeStr(ld['vehicleEngine'] && ld['vehicleEngine']['fuelType'] || ld['fuelType']);
if (fuelRaw) {
  var fuelLower = fuelRaw.toLowerCase();
  if (fuelLower.includes('diesel') || fuelLower.includes('diésel'))  fuel = 'Diesel';
  else if (fuelLower.includes('gasolin') || fuelLower.includes('petrol')) fuel = 'Gasolina';
  else if (fuelLower.includes('electr'))                               fuel = 'Eléctrico';
  else if (fuelLower.includes('hybrid') || fuelLower.includes('híbrid')) fuel = 'Híbrido';
  else fuel = fuelRaw;
}
if (!fuel) {
  var fuelMatch = html.match(/"fuelType"\s*:\s*"([^"]+)"/i);
  if (fuelMatch && fuelMatch[1]) {
    var fl = fuelMatch[1].toLowerCase();
    if (fl.includes('diesel') || fl.includes('diésel'))          fuel = 'Diesel';
    else if (fl.includes('gasolin') || fl.includes('petrol'))    fuel = 'Gasolina';
    else if (fl.includes('electr'))                              fuel = 'Eléctrico';
    else if (fl.includes('hybrid') || fl.includes('híbrid'))    fuel = 'Híbrido';
    else fuel = fuelMatch[1];
  }
}

// ── transmission ──────────────────────────────────────────────
var transmission = null;
var transRaw = safeStr(ld['vehicleTransmission']);
if (transRaw) {
  var tl = transRaw.toLowerCase();
  if (tl.includes('auto') || tl.includes('dct') || tl.includes('cvt') || tl.includes('dsg')) transmission = 'Automatica';
  else if (tl.includes('manual')) transmission = 'Manual';
  else transmission = transRaw;
}
if (!transmission) {
  var transMatch = html.match(/"vehicleTransmission"\s*:\s*"([^"]+)"/i) ||
                   html.match(/"gearType"\s*:\s*"([^"]+)"/i);
  if (transMatch && transMatch[1]) {
    var tl2 = transMatch[1].toLowerCase();
    if (tl2.includes('auto') || tl2.includes('dct') || tl2.includes('dsg')) transmission = 'Automatica';
    else if (tl2.includes('manual')) transmission = 'Manual';
    else transmission = transMatch[1];
  }
}

// ── power_cv / power_kw ───────────────────────────────────────
var power_cv = null;
var power_kw = null;
var engineObj = ld['vehicleEngine'] || {};
var powerRaw = safeStr(engineObj['enginePower']) || '';
var cvMatch = powerRaw.match(/(\d+)\s*(?:CV|PS|HP)/i);
var kwMatch = powerRaw.match(/(\d+)\s*kW/i);
if (cvMatch && cvMatch[1]) power_cv = parseInt(cvMatch[1], 10);
if (kwMatch && kwMatch[1]) power_kw = parseInt(kwMatch[1], 10);

// ── displacement ──────────────────────────────────────────────
var displacement = null;
var dispRaw = safeStr(engineObj['engineDisplacement']) || '';
var dispMatch = dispRaw.match(/(\d+)/);
if (dispMatch && dispMatch[1]) displacement = parseInt(dispMatch[1], 10);

// ── co2 ───────────────────────────────────────────────────────
var co2 = null;
var co2Raw = safeStr(ld['emissionsCO2']) || '';
var co2Match = co2Raw.match(/([\d,\.]+)\s*g\/km/i);
if (co2Match && co2Match[1]) co2 = parseFloat(co2Match[1].replace(',', '.'));

// ── consumption ───────────────────────────────────────────────
var consumption = null;
var consRaw = safeStr(ld['fuelConsumption']) || '';
var consMatch = consRaw.match(/([\d,\.]+)\s*l\/100/i);
if (consMatch && consMatch[1]) consumption = parseFloat(consMatch[1].replace(',', '.'));

// ── next_itv ──────────────────────────────────────────────────
var next_itv = null;
var itvMatch = html.match(/ITV\s+v[áa]lida\s+hasta[:\s]*(\d{1,2})\/(\d{1,2})\/(\d{2,4})/i);
if (itvMatch) {
  var itvDay   = itvMatch[1].padStart(2, '0');
  var itvMonth = itvMatch[2].padStart(2, '0');
  var itvYear  = itvMatch[3];
  if (itvYear.length === 2) itvYear = '20' + itvYear;
  next_itv = itvYear + '-' + itvMonth + '-' + itvDay;
}

// ── environmental_label — inferida de Euro + combustible ──────
var environmental_label = null;
var emStd = safeStr(ld['meetsEmissionStandard']) || '';
var euroMatch = emStd.match(/EURO\s*(\d+)/i);
if (!euroMatch) euroMatch = html.match(/EURO\s*(\d+)/i);
var euroNum = euroMatch ? parseInt(euroMatch[1], 10) : null;
var fuelLow = (fuel || '').toLowerCase();

if (fuelLow.includes('eléctr') || fuelLow.includes('electr')) {
  environmental_label = '0 Emisiones';
} else if (fuelLow.includes('híbrid') || fuelLow.includes('hibrid')) {
  environmental_label = html.match(/plug.in|enchufable/i) ? 'ECO' : 'C';
} else if (euroNum) {
  if (fuelLow.includes('diesel') || fuelLow.includes('diésel')) {
    if (euroNum >= 6)      environmental_label = 'C';
    else if (euroNum >= 4) environmental_label = 'B';
  } else {
    if (euroNum >= 4)      environmental_label = 'C';
    else if (euroNum === 3) environmental_label = 'B';
  }
}

// ── traction ──────────────────────────────────────────────────
var traction = null;
var tracMatch = html.match(/\b(4[Xx]4|4WD|AWD|FWD|RWD|delantera|trasera|tracción\s+total|tracción\s+integral)\b/i);
if (tracMatch && tracMatch[1]) {
  var _tr = tracMatch[1].toLowerCase();
  if (/4x4|4wd|awd|total|integral/.test(_tr)) traction = '4x4';
  else if (/tras|rwd|rear/.test(_tr)) traction = 'Trasera';
  else if (/del|fwd|front/.test(_tr)) traction = 'Delantera';
}

// ── city / location ───────────────────────────────────────────
var city = null;
var location = null;
var addrObj = {};
if (ld['offers'] && ld['offers']['availableAtOrFrom']) {
  addrObj = ld['offers']['availableAtOrFrom']['address'] || ld['offers']['availableAtOrFrom'] || {};
} else if (ld['availableAtOrFrom']) {
  addrObj = ld['availableAtOrFrom']['address'] || ld['availableAtOrFrom'] || {};
}
if (addrObj['addressLocality']) city     = String(addrObj['addressLocality']).trim();
if (addrObj['addressRegion'])   location = String(addrObj['addressRegion']).trim();
if (!city) {
  var cityM = html.match(/"addressLocality"\s*:\s*"([^"]+)"/);
  if (cityM && cityM[1]) city = cityM[1].trim();
}
if (!location) {
  var regionM = html.match(/"addressRegion"\s*:\s*"([^"]+)"/);
  if (regionM && regionM[1]) location = regionM[1].trim();
}
// Si Autohero no informa ubicación → nacional
if (!location && !row.location) location = 'Toda España';
// city = location como fallback
if (!city && location)          city = location;

var province = location;

// ── listed_at ─────────────────────────────────────────────────
var listed_at = null;
var datePosted = safeStr(ld['datePosted']);
if (datePosted) {
  var dpMatch = datePosted.match(/(\d{4}-\d{2}-\d{2})/);
  if (dpMatch) listed_at = dpMatch[1];
}
if (!listed_at) {
  var dpHtml = html.match(/"datePosted"\s*:\s*"([^"]+)"/);
  if (dpHtml && dpHtml[1]) {
    var dpMatch2 = dpHtml[1].match(/(\d{4}-\d{2}-\d{2})/);
    if (dpMatch2) listed_at = dpMatch2[1];
  }
}

// ── finance_price ─────────────────────────────────────────────
var finance_price = null;
var finMatch = html.match(/(\d[\d.,]+)\s*€\s*\/\s*mes/i);
if (!finMatch) finMatch = html.match(/cuota[^0-9]{0,30}(\d[\d.,]+)\s*€/i);
if (finMatch && finMatch[1]) {
  finance_price = parseFloat(finMatch[1].replace(/\./g, '').replace(',', '.'));
  if (isNaN(finance_price)) finance_price = null;
}

// ── Hardcoded ─────────────────────────────────────────────────
var dealer_name       = 'Autohero';
var seller_type       = 'profesional';
var warranty_months   = 12;
var listing_type      = 'compra';
var source_updated_at = new Date().toISOString().slice(0, 10);

// ── SQL builder ───────────────────────────────────────────────
var id = String(row.id || '');
if (!id) return [{ json: { skipped: true, reason: 'no_id' } }];

function esc(v) {
  if (v === null || v === undefined || v === '') return 'NULL';
  if (typeof v === 'number') return isNaN(v) ? 'NULL' : String(v);
  if (typeof v === 'boolean') return v ? 'TRUE' : 'FALSE';
  return "'" + String(v).replace(/'/g, "''") + "'";
}

var parts = [];

if (image_url)              parts.push("image_url = "           + esc(image_url));
if (images_arr.length > 0)  parts.push("images = "             + esc(JSON.stringify(images_arr)));
if (body_type)              parts.push("body_type = "           + esc(body_type));
if (doors !== null)         parts.push("doors = "               + esc(doors));
if (seats !== null)         parts.push("seats = "               + esc(seats));
if (color)                  parts.push("color = "               + esc(color));
if (fuel && !row.fuel)      parts.push("fuel = "                + esc(fuel));
if (transmission)           parts.push("transmission = "        + esc(transmission));
if (power_cv !== null)      parts.push("power_cv = "            + esc(power_cv));
if (power_kw !== null)      parts.push("power_kw = "            + esc(power_kw));
if (displacement !== null)  parts.push("displacement = "        + esc(displacement));
if (co2 !== null)           parts.push("co2 = "                 + esc(co2));
if (consumption !== null)   parts.push("consumption = "         + esc(consumption));
if (next_itv)               parts.push("next_itv = "            + esc(next_itv));
if (environmental_label && !row.environmental_label) parts.push("environmental_label = " + esc(environmental_label));
if (traction)               parts.push("traction = "            + esc(traction));
if (city)                   parts.push("city = "                + esc(city));
if (location)               parts.push("location = "            + esc(location));
if (province)               parts.push("province = "            + esc(province));
if (listed_at)              parts.push("listed_at = "           + esc(listed_at));
if (finance_price !== null) parts.push("finance_price = "       + esc(finance_price));

parts.push("dealer_name = "       + esc(dealer_name));
parts.push("seller_type = "       + esc(seller_type));
parts.push("warranty_months = "   + esc(warranty_months));
parts.push("listing_type = "      + esc(listing_type));
parts.push("source_updated_at = " + esc(source_updated_at));

// Marcar SIEMPRE el intento para no re-scrapear cada noche las ofertas incompletables
parts.push("enrich_tried_at = NOW()");

var updateSql = 'UPDATE moveadvisor_market_offers SET ' + parts.join(', ') + " WHERE id = '" + id.replace(/'/g, "''") + "'";

return [{
  json: {
    id: id,
    updateSql: updateSql,
    hasUpdates: true,
    extracted: {
      image_url: image_url, images: images_arr.length,
      body_type: body_type, doors: doors, seats: seats, color: color,
      fuel: fuel, transmission: transmission, power_cv: power_cv,
      power_kw: power_kw, displacement: displacement, co2: co2,
      consumption: consumption, next_itv: next_itv,
      environmental_label: environmental_label, traction: traction,
      city: city, location: location, listed_at: listed_at,
      finance_price: finance_price
    }
  }
}];
